static bool IsAllowedUrl(Uri uri)
{
    // Only allow http and https schemes
    if (uri.Scheme != "http" && uri.Scheme != "https")
    {
        return false;
    }

    var host = uri.Host.ToLowerInvariant();

    // Block localhost and loopback
    if (host == "localhost" || host == "127.0.0.1" || host == "::1" || host == "[::1]")
    {
        return false;
    }

    // Block metadata endpoints commonly used in cloud environments
    if (host == "169.254.169.254" || host == "metadata.google.internal")
    {
        return false;
    }

    // Try to parse as IP address and block private ranges
    if (System.Net.IPAddress.TryParse(host, out var ipAddress))
    {
        var bytes = ipAddress.GetAddressBytes();

        // 10.0.0.0/8
        if (bytes.Length == 4 && bytes[0] == 10)
            return false;

        // 172.16.0.0/12
        if (bytes.Length == 4 && bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
            return false;

        // 192.168.0.0/16
        if (bytes.Length == 4 && bytes[0] == 192 && bytes[1] == 168)
            return false;

        // 0.0.0.0
        if (bytes.Length == 4 && bytes.All(b => b == 0))
            return false;

        // 169.254.0.0/16 (link-local)
        if (bytes.Length == 4 && bytes[0] == 169 && bytes[1] == 254)
            return false;
    }

    return true;
}